#!/usr/bin/env node
/**
 * inject-remaining-scripts.js
 * Generates 10-page learning scripts for all 13 remaining lessons
 * and writes them into drone_training.json.
 */
const fs = require('fs');
const path = require('path');

const jsonPath = path.join(__dirname, '..', 'courses', 'drone_training.json');
const data = JSON.parse(fs.readFileSync(jsonPath, 'utf8'));

function makeScript(pages) {
  return pages.map((p, i) => ({
    page: i + 1,
    title: p.title,
    content: p.content,
    key_takeaways: p.key_takeaways
  }));
}

